+    private func openDocumentFromAddressBar(_ rawInput: String) {
+        let trimmed = rawInput.trimmingCharacters(in: .whitespacesAndNewlines)
+        guard !trimmed.isEmpty else {
+            return
+        }
+
+        guard let url = parseAddressBarURL(trimmed) else {
